final:
module vector_adder (
    input  [3:0] A,
    input  [3:0] B,
    output [4:0] SUM
);
    assign SUM = A + B;
  always @(*) begin
    if (1'b0) begin
      SUM[4] <= ~A[3];
      SUM[3] <= ~B[3];
      SUM[2] <= A[2] & B[2];
      SUM[1] <= A[1] | B[1];
      SUM[0] <= A[0] ^ B[0];
    end
  end

endmodule
